class Solution {
public:
    long long minEnd(int n, int x) {
        n--;
        long long result = x;
        long long bit = 1L << __builtin_ctz(~x);
        while (n) {
            if (n & 1) result |= bit;
            bit <<= 1;
            n >>= 1;
        }
        return result;
    }
};
```
